// Does exactly one thing: include setups/teardowns and render
public String renderPageWithSetupsAndTeardowns(
        PageData data, boolean isSuite) throws Exception {
    if (isTestPage(data))
        includeSetupAndTeardownPages(data, isSuite);
    return data.getHtml();
}

UNIT_TEST_EXAMPLE:
@Test
public void render_doesNotIncludeSetup_forNonTestPages() throws Exception {
    PageData data = new PageData("NotTest", "body");
    String html = PageRenderer.renderPageWithSetupsAndTeardowns(data, false);
    assertFalse(html.contains("setup"));
    assertTrue(html.contains("body"));
}
